class Command {
  constructor() { this._options = []; this._values = {}; }
  option(flags) {
    const long = String(flags).split(/[ ,|]+/).find((part) => part.startsWith('--'));
    if (long) {
      const name = long.replace(/^--/, '').replace(/[ <[].*$/, '').replace(/-([a-z])/g, (_, char) => char.toUpperCase());
      this._options.push({ long: '--' + long.replace(/^--/, '').replace(/[ <[].*$/, ''), name });
    }
    return this;
  }
  parse(argv = process.argv) {
    for (let index = 2; index < argv.length; index++) {
      const arg = argv[index];
      const option = this._options.find((entry) => arg === entry.long || arg.startsWith(entry.long + '='));
      if (!option) continue;
      this._values[option.name] = arg.includes('=') ? arg.slice(arg.indexOf('=') + 1) : argv[++index];
    }
    return this;
  }
  opts() { return { ...this._values }; }
}
module.exports = { Command, program: new Command() };

