const fs = require('node:fs');
function parse(source) {
  const output = {};
  for (const line of String(source).split(/\r?\n/)) {
    const match = /^\s*([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)?\s*$/.exec(line);
    if (!match) continue;
    output[match[1]] = (match[2] || '').replace(/^['"]|['"]$/g, '');
  }
  return output;
}
function config(options = {}) {
  const parsed = parse(fs.readFileSync(options.path || '.env', 'utf8'));
  for (const [key, value] of Object.entries(parsed)) if (process.env[key] === undefined) process.env[key] = value;
  return { parsed };
}
module.exports = { parse, config };

